<script setup lang="ts">
import{computed,onMounted,ref,watch}from'vue';import{useRouter}from'vue-router';import{Search,Upload,Star,RefreshCw,FolderOpen}from'lucide-vue-next';import DesignCard from '@/components/catalog/DesignCard.vue';import DesignModal from '@/components/catalog/DesignModal.vue';import LoadingSpinner from '@/components/ui/LoadingSpinner.vue';import{catalogService}from '@/services/catalogService';import{apiErrorMessage}from '@/composables/useApiError';import type{Categoria,DesenhoCard,DesenhoDetalhe}from '@/types/api';
const router=useRouter(),items=ref<DesenhoCard[]>([]),categories=ref<Categoria[]>([]),total=ref(0),loading=ref(true),error=ref(''),query=ref(''),selectedCategory=ref<number|null>(null),favorites=ref(false),detail=ref<DesenhoDetalhe|null>(null),detailLoading=ref(false);let timer:number|undefined;
const filtered=computed(()=>selectedCategory.value===null?items.value:items.value.filter(d=>d.categoria?.id===selectedCategory.value));
async function load(){loading.value=true;error.value='';try{const result=await catalogService.list({busca:query.value.trim()||undefined,favorito:favorites.value||undefined,por_pagina:100});items.value=result.itens;total.value=result.total}catch(e){error.value=apiErrorMessage(e,'Não foi possível carregar seu catálogo.')}finally{loading.value=false}}
async function loadCategories(){try{categories.value=await catalogService.categories()}catch{/* catálogo continua utilizável */}}
watch(query,()=>{clearTimeout(timer);timer=window.setTimeout(load,300)});watch(favorites,load);
async function toggleFavorite(design:DesenhoCard|DesenhoDetalhe){const before=design.favorito;design.favorito=!before;try{await catalogService.favorite(design.id,!before);if(favorites.value&&before)items.value=items.value.filter(i=>i.id!==design.id)}catch{design.favorito=before}}
async function openDetail(id:number){detailLoading.value=true;try{detail.value=await catalogService.detail(id)}catch(e){error.value=apiErrorMessage(e,'Não foi possível abrir os detalhes.')}finally{detailLoading.value=false}}
onMounted(()=>{load();loadCategories()})
</script>
<template><section class="mx-auto max-w-[1500px]"><header class="flex flex-col justify-between gap-5 lg:flex-row lg:items-center"><div><h1 class="font-serif text-4xl text-purple md:text-5xl">Seu catálogo de bordados</h1><p class="mt-2 text-muted">Encontre rapidamente a matriz que você precisa.</p></div><button class="primary-button self-start" @click="router.push('/importar')"><Upload :size="19"/>Importar matrizes</button></header><div class="mt-9 flex flex-col items-stretch gap-3 lg:flex-row lg:items-center"><label class="relative flex-1"><Search class="absolute left-4 top-1/2 -translate-y-1/2 text-muted" :size="21"/><input v-model="query" class="field py-4 pl-12 text-base" placeholder="Busque por nome ou categoria" aria-label="Buscar desenhos"/></label><p class="whitespace-nowrap text-sm text-muted"><strong class="text-purple">{{selectedCategory===null?total:filtered.length}}</strong> desenhos no catálogo</p></div><div class="mt-5 flex flex-wrap gap-2"><button :class="['rounded-full px-4 py-2 text-sm font-medium transition',selectedCategory===null&&!favorites?'bg-terracotta text-white':'border border-line bg-white text-muted']" @click="selectedCategory=null;favorites=false">Todos</button><button v-for="category in categories" :key="category.id" :class="['rounded-full px-4 py-2 text-sm font-medium transition',selectedCategory===category.id?'bg-terracotta text-white':'border border-line bg-white text-muted']" @click="selectedCategory=category.id;favorites=false">{{category.nome}}</button><button :class="['flex items-center gap-2 rounded-full px-4 py-2 text-sm font-medium transition',favorites?'bg-gold text-white':'border border-line bg-white text-muted']" @click="favorites=!favorites;selectedCategory=null"><Star :size="16" :class="favorites?'fill-white':''"/>Favoritos</button></div><div v-if="loading" class="mt-8 grid gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"><div v-for="n in 8" :key="n" class="overflow-hidden rounded-[18px] border border-line bg-white"><div class="aspect-square animate-pulse bg-line/60"></div><div class="space-y-3 p-4"><div class="h-4 w-2/3 animate-pulse rounded bg-line"></div><div class="h-6 w-1/3 animate-pulse rounded-full bg-line"></div></div></div></div><div v-else-if="error" class="mt-12 rounded-2xl border border-line bg-white p-10 text-center"><p class="text-muted">{{error}}</p><button class="primary-button mt-5" @click="load"><RefreshCw :size="18"/>Tentar novamente</button></div><div v-else-if="!filtered.length" class="mt-12 rounded-2xl border border-line bg-white p-12 text-center"><FolderOpen class="mx-auto text-sage" :size="42"/><h2 class="mt-4 font-serif text-2xl text-purple">{{query||favorites||selectedCategory?'Nenhum desenho encontrado':'Seu catálogo está esperando o primeiro bordado'}}</h2><p class="mt-2 text-sm text-muted">{{query||favorites||selectedCategory?'Tente ajustar sua busca ou os filtros.':'Importe uma matriz .PES para começar.'}}</p></div><div v-else class="mt-8 grid gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"><DesignCard v-for="design in filtered" :key="design.id" :design="design" @open="openDetail" @favorite="toggleFavorite"/></div></section><div v-if="detailLoading" class="fixed inset-0 z-[60] flex items-center justify-center bg-ink/60 text-white"><LoadingSpinner/></div><DesignModal v-if="detail" :design="detail" @close="detail=null" @favorite="toggleFavorite"/></template>
